class Solution:
    def fizzBuzz(self, n):
        out = []
        for i in range(1, n + 1):
            label = ''
            if i % 3 == 0:
                label += 'Fizz'
            if i % 5 == 0:
                label += 'Buzz'
            out.append(label if label else str(i))
        return out

